--
-- Name: ensure_z_side_patchpanel(text, text, text, text, integer, text, text, text, integer, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ensure_z_side_patchpanel(p_customer_name text, p_room text, p_rack_label text, p_pp_number text, p_rack_unit integer DEFAULT NULL::integer, p_room_code text DEFAULT NULL::text, p_cage_no text DEFAULT NULL::text, p_panel_type text DEFAULT 'PATCHPANEL'::text, p_total_ports integer DEFAULT 96, p_notes text DEFAULT 'auto-created from audit'::text) RETURNS public.patchpanel_instances
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_customer_id integer;
    v_room text;
    v_rack_label text;
    v_pp_number text;
    v_row public.patchpanel_instances%ROWTYPE;
BEGIN
    -- sanitize inputs
    v_pp_number   := NULLIF(trim(p_pp_number), '');
    v_room        := NULLIF(trim(p_room), '');
    v_rack_label  := NULLIF(trim(p_rack_label), '');

    IF v_pp_number IS NULL THEN
        RAISE EXCEPTION 'pp_number is required';
    END IF;

    IF p_customer_name IS NULL OR NULLIF(trim(p_customer_name), '') IS NULL THEN
        RAISE EXCEPTION 'customer_name is required';
    END IF;

    IF v_room IS NULL THEN
        RAISE EXCEPTION 'room is required';
    END IF;

    -- 1) ensure customer exists
    VALUES (trim(p_customer_name))
    ON CONFLICT (name)
    DO UPDATE SET name = EXCLUDED.name
    RETURNING id INTO v_customer_id;

    -- fallback rack label if empty
    IF v_rack_label IS NULL THEN
        v_rack_label := 'AUTO';
    END IF;

    -- 2) upsert patchpanel_instances by pp_number
        pp_number,
        customer_id,
        room,
        room_code,
        cage_no,
        rack_label,
        rack_unit,
        side,
        panel_type,
        total_ports,
        notes
    )
    VALUES (
        v_pp_number,
        v_customer_id,
        v_room,
        p_room_code,
        p_cage_no,
        v_rack_label,
        p_rack_unit,
        'Z',
        p_panel_type,
        p_total_ports,
        p_notes
    )
    ON CONFLICT (pp_number)
    DO UPDATE SET
        customer_id = EXCLUDED.customer_id,
        room        = EXCLUDED.room,
        room_code   = COALESCE(EXCLUDED.room_code, public.patchpanel_instances.room_code),
        cage_no     = COALESCE(EXCLUDED.cage_no,   public.patchpanel_instances.cage_no),
        rack_label  = EXCLUDED.rack_label,
        rack_unit   = COALESCE(EXCLUDED.rack_unit, public.patchpanel_instances.rack_unit),
        side        = 'Z',
        panel_type  = COALESCE(EXCLUDED.panel_type, public.patchpanel_instances.panel_type),
        total_ports = COALESCE(EXCLUDED.total_ports, public.patchpanel_instances.total_ports),
        notes       = COALESCE(EXCLUDED.notes, public.patchpanel_instances.notes),
        updated_at  = now()
    RETURNING * INTO v_row;

    RETURN v_row;
END;
$$;


--
-- Name: norm_room(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.norm_room(x text) RETURNS text
    LANGUAGE sql IMMUTABLE
    AS $_$
  SELECT
    regexp_replace(
      regexp_replace(
        regexp_replace(
          upper(replace(trim(x), ' ', '')),
          '^M', ''                      -- führendes M weg
        ),
        'S0+([0-9]+)$', 'S\1'           -- S06 -> S6
      ),
      '\.0+([0-9])', '.\1'              -- 5.04 -> 5.4  (falls gewünscht)
    );
$_$;


--
-- Name: normalize_room(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.normalize_room(p text) RETURNS text
    LANGUAGE plpgsql
    AS $_$
DECLARE
  s text;
  main_part text;
  s_part text;
  m1 text;
  m2 text;
BEGIN
  IF p IS NULL THEN
    RETURN NULL;
  END IF;

  -- cleanup
  s := upper(trim(p));
  s := replace(s, ' ', '');
  s := replace(s, 'M', '');       -- remove leading M
  s := replace(s, ',', '.');

  -- split into main + optional S-part
  main_part := regexp_replace(s, 'S.*$', '');
  s_part := NULLIF(regexp_replace(s, '^.*?(S.*)$', '\1'), s);

  -- normalize main part: "5.04" -> "5.4"
  IF main_part ~ '^\d+\.\d+$' THEN
    m1 := split_part(main_part, '.', 1);
    m2 := split_part(main_part, '.', 2);
    m2 := ltrim(m2, '0');
    IF m2 = '' THEN m2 := '0'; END IF;
    main_part := m1 || '.' || m2;
  END IF;

  -- normalize S-part: "S01" -> "S1"
  IF s_part IS NOT NULL THEN
    s_part := regexp_replace(s_part, '^S0+', 'S');
  END IF;

  RETURN main_part || COALESCE(s_part, '');
END;
$_$;


--
-- Name: trg_customer_racks_sync_room_opencolo(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_customer_racks_sync_room_opencolo() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Rack Label immer trimmen (gegen '0702 ' / ' 0702' Mist)
  NEW.rack_label := BTRIM(NEW.rack_label);

  SELECT
    cl.room,
    (COALESCE(NULLIF(BTRIM(cl.cage_no), ''), '') = '')
  INTO
    NEW.room,
    NEW.is_opencolo
  FROM customer_locations cl
  WHERE cl.id = NEW.location_id;

  IF NEW.room IS NULL THEN
    RAISE EXCEPTION 'customer_racks.location_id % not found in customer_locations', NEW.location_id;
  END IF;

  RETURN NEW;
END;
$$;


