--
-- Name: migration_audit_lines_norm; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.migration_audit_lines_norm AS
 SELECT id,
    source_file,
    source_row,
    customer_name,
    system_name,
    room,
    rack_code,
    switch_name,
    switch_port,
    a_pp_number,
    a_port_label,
    z_pp_number,
    z_port_label,
    product_id,
    serial_number,
    backbone_in_instance_id,
    backbone_in_port_label,
    backbone_out_instance_id,
    backbone_out_port_label,
    tech_comment,
    audit_status,
    audited_by,
    audited_at,
    linked_cc_id,
    a_pp_raw,
    z_pp_raw,
    a_eqx_port,
    z_eqx_port,
    pp1_raw,
    pp1_number,
    pp1_port_label,
    pp1_eqx_port,
    pp2_raw,
    pp2_number,
    pp2_port_label,
    pp2_eqx_port,
    TRIM(BOTH FROM switch_name) AS switch_name_norm,
    TRIM(BOTH FROM switch_port) AS switch_port_norm,
    regexp_replace(regexp_replace(regexp_replace(replace(replace(upper(TRIM(BOTH FROM room)), ' '::text, ''::text), 'M'::text, ''::text), '^(\d+)\.0(\d)'::text, '\1.\2'::text), 'S0+(\d+)$'::text, 'S\1'::text), 'S0+(\d+)'::text, 'S\1'::text) AS room_norm
   FROM public.migration_audit_lines l;


