--
-- Name: pp_instances_norm; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.pp_instances_norm AS
 SELECT pp_instance_id,
    room,
    ru,
    peer_pp_instance_id,
    regexp_replace(regexp_replace(regexp_replace(replace(replace(upper(TRIM(BOTH FROM room)), ' '::text, ''::text), 'M'::text, ''::text), '^(\d+)\.0(\d)'::text, '\1.\2'::text), 'S0+(\d+)$'::text, 'S\1'::text), 'S0+(\d+)'::text, 'S\1'::text) AS room_norm,
    split_part((peer_pp_instance_id)::text, '/'::text, 1) AS peer_room_raw,
    regexp_replace(regexp_replace(regexp_replace(replace(replace(upper(TRIM(BOTH FROM split_part((peer_pp_instance_id)::text, '/'::text, 1))), ' '::text, ''::text), 'M'::text, ''::text), '^(\d+)\.0(\d)'::text, '\1.\2'::text), 'S0+(\d+)$'::text, 'S\1'::text), 'S0+(\d+)'::text, 'S\1'::text) AS peer_room_norm
   FROM archive.pp_instances ppi;


