--
-- Name: pre_cabled_links_norm; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.pre_cabled_links_norm AS
 SELECT id,
    patchpanel_id,
    patchpanel_port,
    patchpanel_pair,
    room,
    switch_name,
    switch_port,
    created_at,
    room_norm,
    public.normalize_room((room)::text) AS room_norm_calc,
    upper(TRIM(BOTH FROM switch_name)) AS switch_name_norm,
    upper(TRIM(BOTH FROM switch_port)) AS switch_port_norm
   FROM public.pre_cabled_links pcl;


